export enum Cursor {
    POINTER,
    SINGLE,
    FILL,
    GRAB,
    TEXT,
    TEXT_ROT,
    DELETE,
    ASSIGN,
    CLEAR,
    INSPECT
}

export enum CellType {
    OPEN,
    BOUNDARY,
    PIT,
    FIELD,
    FIELD_ROT,
    OBJECT,
    LABEL,
}

export enum LabelMode {
    NUMBER = 1,
    ADDRESS,
    TEAM,
    COLOR
}

export enum AutoAssignmentType {
    ASCENDING,
    DESCENDING,
    RANDOM,
    CLEAR
}

interface Point {
    x: number,
    y: number
}

export interface Rectangle extends Point {
    w: number,
    h: number,
}

export interface Cell extends Rectangle{
    type: CellType,
    label?: string | null,
    labelRotated?: boolean,
    ind?: number,
    team?: number;
    address?: string,
    addressGroup?: string | null,
    color?: string
}

export interface PitMapData {
    objects: Cell[],
    minX : number,
    minY: number,
    width: number,
    height: number,
    numbers: boolean,
    addresses: boolean
}

interface Delta {
    dx: number,
    dy: number
}

interface AddRemoveAction {
    op: 'ADD' | 'REMOVE',
    objects: Cell[]
}

interface ShiftAction {
    op: 'SHIFT',
    delta: Delta
}

interface MoveAction {
    op: 'MOVE',
    objects: Cell[],
    delta: Delta
}

interface LabelAction {
    op: 'SET_LABEL',
    obj: Cell,
    old?: string | null,
    label?: string | null
}

type Action = AddRemoveAction | ShiftAction | LabelAction | MoveAction


interface PitAssignment { number: number, address: string, team: number }

type PitClickCallback = (cell : Cell) => void
type PitColorCallback = (cell : Cell) => [string, string]
type PitAssignCallback = (cells : Cell[], mode : LabelMode) => void
type TextSelectCallback = (cell : Cell, callback : (str : string | null) => void) => void
type ErrorCallback = (error : { errType: number, number: string | null, max?: number }) => void

const ZERO_POINT : Point = {x: 0, y: 0} ;

export default class PitMap {
    static CELL_PROPS = {
        [CellType.OPEN]: {
            width: 1,
            height: 1,
            color: 'white',
            hoverColor: 'rgba(225,225,225,.5)',
            labelAllowed: false
        },
        [CellType.BOUNDARY]: {
            width: 1,
            height: 1,
            color: 'black',
            hoverColor: 'rgba(0,0,0,.5)',
            labelAllowed: false
        },
        [CellType.PIT]: {
            width: 2,
            height: 2,
            color: 'orange',
            printColor: 'white',
            hoverColor: 'rgba(255, 165, 0, .5)',
            labelAllowed: false
        },
        [CellType.FIELD]: {
            width: 5,
            height: 3,
            color: 'white',
            hoverColor: 'rgba(0, 255, 255, .5)',
            labelAllowed: true
        },
        [CellType.FIELD_ROT]: {
            width: 3,
            height: 5,
            color: 'white',
            hoverColor: 'rgba(0, 255, 255, .5)',
            labelAllowed: true
        },
        [CellType.OBJECT]: {
            width: 1,
            height: 1,
            color: 'white',
            hoverColor: 'rgba(255,255,255,.5)',
            labelAllowed: true
        },
        [CellType.LABEL]: {
            width: 1,
            height: 1,
            color: 'white',
            hoverColor: 'rgba(200,200,200,.5)',
            labelAllowed: true
        },
    }
    static ERROR_ILLEGAL_NUMBER = 1;
    static ERROR_DUPLICATE_PIT = 2;
    static BASE_CELL_SIZE = 20;
    canvas : HTMLCanvasElement;
    g : CanvasRenderingContext2D;
    highlighted? : Cell;
    cursor = Cursor.POINTER;
    hover : Point | null = null;
    dragging = false;
    dragStart : Point | null = null;
    dragCurrent : Point | null = null;
    selectStart : Point | null = null;
    selectEnd : Point | null = null;
    grabbedItem : Cell | null = null;
    grabOffset : Point = ZERO_POINT;
    grabCurrent : Point = ZERO_POINT;
    /* Used for cursor select, not fill select */
    pointerSelected: Cell[] = [];
    pointerSelectStart : Point | null = null;
    pointerCurrent: Point | null = null;
    editing = false;
    assigning = false;
    cellType = CellType.OPEN;
    zoom = 1;
    undoStack : Action[] = [];
    redoStack : Action[] = [];
    objects : Cell[] = [];
    pitClickCallback? : PitClickCallback;
    pitColorCallback? : PitColorCallback;
    pitLabelMode = LabelMode.NUMBER;
    pitAssignCallback? : PitAssignCallback;
    assignError? : ErrorCallback;
    CELL_SIZE = PitMap.BASE_CELL_SIZE;
    minSize = false;
    printing: boolean = false;
    printPitColors: boolean = false;
    displayTeamNumbers: Record<number, string> = {};
    activeGroup = 'A';
    increment = 1;
    textSelectCallback?: TextSelectCallback;

    constructor({id, textSelectCallback, pitColorCallback, minView} : {
        id: string,
        textSelectCallback?: TextSelectCallback,
        pitColorCallback?: PitColorCallback
        minView?: boolean
    }) {
        const canvasElement = document.getElementById(id);
        if(!canvasElement) {
            throw `Element '${id}' not found`
        }
        this.canvas = canvasElement as HTMLCanvasElement;
        const context = this.canvas.getContext('2d');
        if(!context) {
            throw `Could not build 2d context`
        }
        this.g = context;
        this.g.save();
        this.minSize = minView || false;
        this.pitColorCallback = pitColorCallback;
        this.textSelectCallback = textSelectCallback;
        this.canvas.addEventListener('click', this.clickListener)
        this.canvas.addEventListener('mousedown', this.mouseDownListener);
        this.canvas.addEventListener('mouseup', this.mouseUpListener);
        this.canvas.addEventListener('mousemove', this.mouseMoveListener);
        this.canvas.addEventListener('mouseleave', this.mouseLeaveListener);
        this.draw();
    }

    destroy() {
        this.canvas.removeEventListener('click', this.clickListener);
        this.canvas.removeEventListener('mousedown', this.mouseDownListener);
        this.canvas.removeEventListener('mouseup', this.mouseUpListener);
        this.canvas.removeEventListener('mousemove', this.mouseMoveListener);
        this.canvas.removeEventListener('mouseleave', this.mouseLeaveListener);
        this.g.reset();
    }

    clickListener = (e: MouseEvent) => {
        let pt = this.getGridCoords({x: e.offsetX, y: e.offsetY});
        if (this.editing) {
            if (this.cursor === Cursor.SINGLE) {
                // TODO if type = OPEN, delete any covered objects
                let obj = this.getObject(this.cellType, pt, true);
                const intersecting = this.getIntersectingObjects(obj);
                if (intersecting.length === 0 && this.cellType === CellType.OPEN) {
                    return; // dont put empty on top of empty.
                }
                this.objects.push(obj);
                this.pushUndo({op: 'ADD', objects: [obj]});
                this.draw();
            } else if (this.cursor === Cursor.DELETE) {
                const intersecting = this.getIntersectingObjects(Object.assign({w: 0, h: 0}, pt));
                if (intersecting.length > 0) {
                    let obj = intersecting[intersecting.length - 1];
                    obj.ind = this.objects.indexOf(obj);
                    if (obj.ind > -1) {
                        this.objects.splice(obj.ind, 1)
                    }
                }
                this.renumberObjects();
                this.pushUndo({op: 'REMOVE', objects: intersecting});
                this.draw();
            } else if (this.cursor === Cursor.TEXT || this.cursor == Cursor.TEXT_ROT) {
                const intersecting = this.getIntersectingObjects(Object.assign({
                    w: 0,
                    h: 0
                }, pt)).filter(x => PitMap.CELL_PROPS[x.type].labelAllowed);
                if (intersecting.length && this.textSelectCallback) {
                    this.textSelectCallback(intersecting[0], (label) => {
                        this.pushUndo({
                            op: 'SET_LABEL',
                            obj: intersecting[0],
                            old: intersecting[0].label,
                            label: label
                        });
                        intersecting[0].label = label;
                        intersecting[0].labelRotated = this.cursor == Cursor.TEXT_ROT;
                        this.draw();
                    })
                }
            } else if (this.cursor === Cursor.GRAB || this.cursor === Cursor.POINTER) {
                // Grabbed! - ignoring click event
            }
        } else if (!this.assigning || this.cursor === Cursor.INSPECT) {
            const pits = this.getIntersectingObjects(Object.assign({
                w: 0,
                h: 0
            }, pt)).filter(x => x.type === CellType.PIT);
            if (pits.length === 0) {
                return;
            }
            if(this.pitClickCallback) {
                this.pitClickCallback(pits[0]);
            }
        }
    }

    mouseDownListener = (e: MouseEvent) => {
        if(!this.editing && !this.assigning) {
            return;
        }
        const eventPoint = {x: e.offsetX, y: e.offsetY};
        const intersectionTest = Object.assign(this.getGridCoords(eventPoint), {w: 0, h: 0});
        if (this.cursor === Cursor.FILL || this.cursor === Cursor.ASSIGN || this.cursor === Cursor.CLEAR) {
            this.dragging = this.cursor === Cursor.FILL || this.cursor === Cursor.CLEAR || (this.cursor === Cursor.ASSIGN && (this.pitLabelMode === LabelMode.ADDRESS || this.pitLabelMode === LabelMode.COLOR));
            this.dragStart = eventPoint;
            this.dragCurrent = this.dragStart;
            this.selectStart = null;
            this.selectEnd = null;
        } else if (this.cursor === Cursor.GRAB) {
            const grabCandidates = this.getIntersectingObjects(intersectionTest);
            if (grabCandidates.length > 0) {
                this.grabbedItem = grabCandidates[grabCandidates.length - 1];
                // This needs to be how far from the cursor the corner of the grabbed item is - requires pixel coords
                this.grabOffset = this.grabbedItem ? {x: e.offsetX - (this.grabbedItem.x * this.CELL_SIZE), y: e.offsetY - (this.grabbedItem.y * this.CELL_SIZE)} : ZERO_POINT;
                this.grabCurrent = eventPoint;
                this.setCursor(Cursor.GRAB); // update rendered cursor to grabbing
            }
        } else if (this.cursor === Cursor.POINTER) {
            this.pointerSelectStart = eventPoint;
            if (this.pointerSelected.length > 0 && this.pointerSelected.some(x => intersect(intersectionTest, x))) {
                // dragging the selected items
                this.pointerCurrent = eventPoint;
            } else {
                // Creating a new selection grid
                this.pointerSelected = [];
            }
        }
    }

    mouseUpListener = (e: MouseEvent) => {
        if(!this.editing && !this.assigning) {
            return;
        }
        if (this.dragging) {
            this.selectStart = this.dragStart;
            this.selectEnd = this.dragCurrent;
            this.dragging = false;
            this.draw();
        }
        if (this.grabbedItem) {
            // drop the grabbed item & update it
            const gridCoords = this.getGridCoords({x: e.offsetX - this.grabOffset.x, y: e.offsetY - this.grabOffset.y});
            if (gridCoords.x !== this.grabbedItem.x || gridCoords.y !== this.grabbedItem.y) {
                this.pushUndo({
                    op: 'MOVE',
                    objects: [this.grabbedItem],
                    delta: {dx: gridCoords.x - this.grabbedItem.x, dy: gridCoords.y - this.grabbedItem.y}
                });
                this.grabbedItem.x = gridCoords.x;
                this.grabbedItem.y = gridCoords.y;
            }
            this.grabbedItem = null;
            this.grabOffset = ZERO_POINT;
            this.grabCurrent = ZERO_POINT;
            this.setCursor(Cursor.GRAB); // update rendered cursor to grab
        }
        if (this.cursor === Cursor.POINTER) {
            // set the pointerSelected array
            const curr = {x: e.offsetX, y: e.offsetY};
            const rect = this.getRectFromCorners(this.getGridCoords(this.pointerSelectStart ?? curr), this.getGridCoords(curr))
            forceQ3(rect);
            if (this.pointerSelected.length === 0) {
                this.pointerSelected = this.getIntersectingObjects(rect);
            } else {
                const gridDeltaPt = this.getGridCoords({x: this.pointerCurrent!.x - this.pointerSelectStart!.x, y: this.pointerCurrent!.y - this.pointerSelectStart!.y})
                const gridDelta = {dx: gridDeltaPt.x, dy: gridDeltaPt.y};
                for (let obj of this.pointerSelected) {
                    obj.x += gridDelta.dx;//newLoc.x;
                    obj.y += gridDelta.dy;
                }
                this.pushUndo({
                    op: 'MOVE',
                    objects: [...this.pointerSelected],
                    delta: gridDelta
                });
            }
            this.pointerCurrent = null;
            this.pointerSelectStart = null;
            this.draw();
        }
        if (this.assigning && (this.cursor === Cursor.ASSIGN || this.cursor === Cursor.SINGLE || this.cursor == Cursor.CLEAR)) {
            let selectRect = Object.assign(this.getGridCoords({x: e.offsetX, y: e.offsetY}), {w: 0, h: 0});
            if ((this.pitLabelMode === LabelMode.ADDRESS || this.pitLabelMode === LabelMode.COLOR || this.cursor == Cursor.CLEAR) && this.selectStart && this.selectEnd) {
                selectRect = this.getRectFromCorners(this.getGridCoords(this.selectStart), this.getGridCoords(this.selectEnd));
                forceQ3(selectRect);
            }
            const pits = this.getIntersectingObjects(selectRect).filter(x => x.type === CellType.PIT);
            console.log(pits, this.cursor, this.pitLabelMode)
            if(pits.length > 0) {
                if (this.cursor == Cursor.CLEAR) {
                    this.assign(pits, this.pitLabelMode, null);
                } else if (this.pitAssignCallback) {
                    this.pitAssignCallback(pits, this.pitLabelMode);
                }
            }
        }
    }

    mouseMoveListener = (e: MouseEvent) => {
        const offsetPoint = {x: e.offsetX, y: e.offsetY};
        if (this.dragging) {
            this.dragCurrent = offsetPoint;
            this.draw();
        } else if (this.grabbedItem) {
            this.grabCurrent = offsetPoint;
            this.draw();
        } else if (this.cursor === Cursor.POINTER && this.pointerSelectStart) {
            this.pointerCurrent = offsetPoint;
            this.draw();
        } else {
            this.dragCurrent = null;
            if (this.cursor === Cursor.SINGLE || this.cursor === Cursor.DELETE) {
                this.hover = offsetPoint;
                this.draw();
            }
        }
    }

    mouseLeaveListener = (e: MouseEvent) => {
        this.hover = null;
        this.grabbedItem = null;
        this.pointerCurrent = null;
        this.pointerSelectStart = null;
        this.draw();
    }

    getObject(type : CellType, pt : Point, num : boolean = false) : Cell {
        const typeGroup = type === CellType.FIELD || type === CellType.FIELD_ROT ? [CellType.FIELD, CellType.FIELD_ROT] : [type];
        return {
            type: this.cellType,
            x: pt.x,
            y: pt.y,
            w: PitMap.CELL_PROPS[this.cellType].width,
            h: PitMap.CELL_PROPS[this.cellType].height,
            label: num && type === CellType.PIT ? this.objects.filter(x => typeGroup.includes(x.type)).length + 1 + "" : null
        }
    }

    getSelectRect() {
        return {
            x: this.selectStart!.x,
            y: this.selectStart!.y,
            w: this.selectEnd!.x - this.selectStart!.x,
            h: this.selectEnd!.y - this.selectStart!.y
        }
    }

    drawCursor() {
        if (this.cursor === Cursor.SINGLE || this.cursor === Cursor.POINTER) {
            this.canvas.style['cursor'] = 'default';
        } else if (this.cursor === Cursor.FILL) {
            this.canvas.style['cursor'] = 'cell';
        } else if (this.cursor === Cursor.GRAB) {
            this.canvas.style['cursor'] = this.grabbedItem ? 'grabbing': 'grab';
        } else if (this.cursor === Cursor.TEXT || this.cursor === Cursor.TEXT_ROT) {
            this.canvas.style['cursor'] = 'text';
        } else if (this.cursor === Cursor.DELETE) {
            this.canvas.style['cursor'] = 'default';
        } else if (this.cursor === Cursor.INSPECT) {
            this.canvas.style['cursor'] = 'help';
        } else if (this.cursor === Cursor.CLEAR) {
            this.canvas.style['cursor'] = 'default';
        } else if (this.cursor === Cursor.ASSIGN) {
            this.canvas.style['cursor'] = 'default';
        }
    }

    draw() {
        // TODO optimize this to only redraw the area that has changed since last draw
        this.g.save();
        this.drawCursor();
        let h = 0;
        let w = 0;
        if (this.minSize) { // render exact size canvas (NOT FOR EDITING!)
            const bb = this.getBoundingBox();
            w = this.CELL_SIZE * bb.w;
            h = this.CELL_SIZE * bb.h;
        } else {
            w = this.CELL_SIZE * Math.floor((this.canvas.parentNode as Element).clientWidth / this.CELL_SIZE);
            h = this.CELL_SIZE * Math.floor(window.innerHeight * .75 / this.CELL_SIZE);
        }
        // https://stackoverflow.com/a/65124939
        this.canvas.height = h * window.devicePixelRatio;
        this.canvas.style.height = h + 'px';
        this.canvas.width = w * window.devicePixelRatio;
        this.canvas.style.width = w + 'px';
        this.g.scale(window.devicePixelRatio, window.devicePixelRatio);

        this.g.clearRect(0, 0, this.canvas.width, this.canvas.height);
        this.g.lineWidth = this.zoom;
        // draw grid
        this.g.fillStyle = 'black';
        this.g.strokeStyle = 'black';
        if (this.editing) {
            for (let x = 0; x < 2000 * this.zoom; x += this.CELL_SIZE) {
                for (let y = 0; y < 2000 * this.zoom; y += this.CELL_SIZE) {
                    this.g.strokeRect(x, y, this.CELL_SIZE, this.CELL_SIZE);
                }
            }
        }

        for (let obj of this.objects) {
            const hoverStyle = this.editing &&
                // 'hover' style if grabbed or if being dragged in a group
                ((!!this.grabbedItem && obj === this.grabbedItem) || (this.pointerSelected.includes(obj) && !!this.pointerCurrent));
            const selectedStyle = this.pointerSelected.includes(obj) && !this.pointerCurrent;
            this.drawObject(obj, hoverStyle, selectedStyle);
        }

        // draw selections:
        if (this.editing) {
            if (this.selectStart && this.selectEnd) {
                let selectRect = this.getSelectRect();
                this.snapToGrid(selectRect);
                this.fillCells(selectRect, 'yellow');
            }
            if (this.dragging) {
                let dragRect = {
                    x: this.dragStart!.x,
                    y: this.dragStart!.y,
                    w: this.dragCurrent!.x - this.dragStart!.x,
                    h: this.dragCurrent!.y - this.dragStart!.y
                };
                this.snapToGrid(dragRect);
                this.fillCells(dragRect, 'yellow');
            }
            if (this.grabbedItem) {
                let obj = Object.assign({}, this.grabbedItem, this.getGridCoords({x: this.grabCurrent.x - this.grabOffset.x, y: this.grabCurrent.y - this.grabOffset.y}));
                this.drawObject(obj, false);
            }
            if (this.pointerSelected.length > 0 && this.pointerCurrent) {
                // draw the group in their intermediate drag location
                for (let obj of this.pointerSelected) {
                    const temp = Object.assign({}, obj, this.getGridCoords({x: this.CELL_SIZE * obj.x + (this.pointerCurrent!.x - this.pointerSelectStart!.x), y: this.CELL_SIZE * obj.y + (this.pointerCurrent!.y - this.pointerSelectStart!.y)}));
                    this.drawObject(temp, false, true);
                }
            }
            // draw hover
            if (this.hover) {
                if (this.cursor === Cursor.SINGLE) {
                    let obj = this.getObject(this.cellType, this.getGridCoords(this.hover));
                    this.drawObject(obj, true);
                } else if (this.cursor === Cursor.DELETE) {
                    this.g.strokeStyle = 'red';
                    for (let obj of this.getIntersectingObjects(Object.assign({
                        w: 0,
                        h: 0
                    }, this.getGridCoords(this.hover)))) {
                        this.g.strokeRect(obj.x * this.CELL_SIZE, obj.y * this.CELL_SIZE, this.CELL_SIZE * obj.w, this.CELL_SIZE * obj.h);
                        this.g.strokeRect(obj.x * this.CELL_SIZE + 1, obj.y * this.CELL_SIZE + 1, this.CELL_SIZE * obj.w - 2, this.CELL_SIZE * obj.h - 2);
                    }
                }
            }
            if (this.pointerCurrent && this.pointerSelected.length === 0) {
                let pointerSelectRect = {
                    x: this.pointerSelectStart!.x,
                    y: this.pointerSelectStart!.y,
                    w: this.pointerCurrent!.x - this.pointerSelectStart!.x,
                    h: this.pointerCurrent!.y - this.pointerSelectStart!.y
                };
                this.g.strokeStyle = '#0078D7';
                this.g.fillStyle = 'rgba(170, 204, 238, .5)';
                this.g.fillRect(pointerSelectRect.x, pointerSelectRect.y, pointerSelectRect.w, pointerSelectRect.h);
                this.g.strokeRect(pointerSelectRect.x, pointerSelectRect.y, pointerSelectRect.w, pointerSelectRect.h);
            }
        } else if (this.assigning) {
            // draw selection square
            if (this.dragging) {
                //
                let dragRect = {
                    x: this.dragStart!.x,
                    y: this.dragStart!.y,
                    w: this.dragCurrent!.x - this.dragStart!.x,
                    h: this.dragCurrent!.y - this.dragStart!.y
                };
                this.g.strokeStyle = '#0078D7';
                this.g.fillStyle = 'rgba(170, 204, 238, .5)';
                this.g.fillRect(dragRect.x, dragRect.y, dragRect.w, dragRect.h);
                this.g.strokeRect(dragRect.x, dragRect.y, dragRect.w, dragRect.h);
            }

        }

        this.g.fillStyle = 'auto';
    }

    drawObject(obj : Cell, hover = false, selectedStyle = false) {
        //this.g.fillStyle = 'black';
        if (obj.type !== CellType.LABEL) { // label is just an object with no border
            this.g.strokeRect(obj.x * this.CELL_SIZE, obj.y * this.CELL_SIZE, this.CELL_SIZE * obj.w, this.CELL_SIZE * obj.h);
        }
        const cellProps = PitMap.CELL_PROPS[obj.type];
        if(obj.type == CellType.PIT && this.pitColorCallback && (!this.printing || this.printPitColors)) {
            this.g.fillStyle = this.pitColorCallback(obj)[0]
        } else if (obj.type === CellType.PIT && obj.color && (!this.printing || this.printPitColors)) {
            this.g.fillStyle = obj.color;
        } else {
            this.g.fillStyle = this.printing ? (!this.printPitColors && 'printColor' in cellProps ? cellProps.printColor : cellProps.color) : (hover ? cellProps.hoverColor : cellProps.color);
        }
        if (obj === this.highlighted) {
            this.g.fillStyle = 'cyan';
        }
        this.g.fillRect(obj.x * this.CELL_SIZE + this.zoom / 2.0, obj.y * this.CELL_SIZE + this.zoom / 2.0, this.CELL_SIZE * obj.w - this.zoom, this.CELL_SIZE * obj.h - this.zoom);
        // 22 x 12 in 25x15 area! = 1.5ft margins = 1.5 * pit_width / 10
        let gap = Math.round(1.5 * this.CELL_SIZE * 2 / 10); //approx scale field to 10x10 pit size
        let fieldWall = Math.round(12 * this.CELL_SIZE * 2 / 10); //approx scale field to 10x10 pit size
        let allianceStation = Math.round(3.5 * this.CELL_SIZE * 2 / 10); //approx scale field to 10x10 pit size
        this.g.fillStyle = 'black';
        if (obj.type === CellType.FIELD) {
            this.g.strokeRect(obj.x * this.CELL_SIZE + gap, obj.y * this.CELL_SIZE + gap, allianceStation, fieldWall);
            this.g.strokeRect(obj.x * this.CELL_SIZE + gap + allianceStation + gap, obj.y * this.CELL_SIZE + gap, fieldWall, fieldWall);
            this.g.strokeRect(obj.x * this.CELL_SIZE + gap + allianceStation + gap + fieldWall + gap, obj.y * this.CELL_SIZE + gap, allianceStation, fieldWall);
        } else if (obj.type === CellType.FIELD_ROT) {
            this.g.strokeRect(obj.x * this.CELL_SIZE + gap, obj.y * this.CELL_SIZE + gap, fieldWall, allianceStation);
            this.g.strokeRect(obj.x * this.CELL_SIZE + gap, obj.y * this.CELL_SIZE + gap + allianceStation + gap, fieldWall, fieldWall);
            this.g.strokeRect(obj.x * this.CELL_SIZE + gap, obj.y * this.CELL_SIZE + gap + allianceStation + gap + fieldWall + gap, fieldWall, allianceStation);
        }
        if (obj.type === CellType.PIT || cellProps.labelAllowed) {
            let text = obj.label;
            if (obj.type === CellType.PIT) {
                switch (this.pitLabelMode) {
                    case LabelMode.NUMBER:
                        text = obj.label;
                        break;
                    case LabelMode.ADDRESS:
                        text = this.getFullAddress(obj);
                        break;
                    case LabelMode.TEAM:
                        text = (obj.team ? (this.displayTeamNumbers[obj.team] || obj.team) : "") + "";
                        break;
                }
            }
            if (text) {
                let test = text;
                if (obj.type === CellType.PIT && this.pitLabelMode === LabelMode.TEAM) {
                    test = "88888"; // force all team numbers to 5-digit fit
                }
                // TODO maybe also consider split on white-space and double-line it. Maybe there is a library for this?
                let f = Math.round(.6 * Math.min(obj.h, obj.w) * this.CELL_SIZE);
                this.g.font = f + 'px sans-serif'
                while (this.g.measureText(test).width >= (obj.labelRotated ? obj.h : obj.w) * this.CELL_SIZE - 2 && f > 0) {
                    f -= 2;
                    this.g.font = f + 'px sans-serif'
                }
                this.g.textAlign = 'center';
                this.g.textBaseline = 'middle';

                if(obj.type == CellType.PIT && this.pitColorCallback && !this.printing) {
                    this.g.fillStyle = this.pitColorCallback(obj)[1]
                }
                let x = Math.round(this.CELL_SIZE * obj.x + this.CELL_SIZE * obj.w / 2);
                let y = Math.round(this.CELL_SIZE * obj.y + this.CELL_SIZE * obj.h / 2);
                this.g.save();
                this.g.translate(x, y);
                if (obj.labelRotated) {
                    this.g.rotate(-Math.PI/2);
                }
                this.g.fillText(text, 0, 0);
                this.g.restore();
            }
        }
        this.g.fillStyle = 'black';
        if (obj.type !== CellType.LABEL) {
            const oldStrokeStyle = this.g.strokeStyle;
            if (selectedStyle && !hover) {
                this.g.strokeStyle = 'cyan';
                this.g.strokeRect(obj.x * this.CELL_SIZE - 1, obj.y * this.CELL_SIZE - 1, this.CELL_SIZE * obj.w + 2, this.CELL_SIZE * obj.h + 2);
            }
            this.g.strokeRect(obj.x * this.CELL_SIZE, obj.y * this.CELL_SIZE, this.CELL_SIZE * obj.w, this.CELL_SIZE * obj.h);
            this.g.strokeStyle = oldStrokeStyle;
        }
    }

    setCursor(cursor : Cursor) {
        this.cursor = cursor;
        this.hover = null;
        this.selectStart = null;
        if ([Cursor.SINGLE, Cursor.FILL, Cursor.TEXT, Cursor.TEXT_ROT, Cursor.DELETE].includes(cursor)) {
            this.pointerSelected = [];
            // If delete is clicked, do we want to popup ask for mass delete of all selected?
        }
        this.draw();
    }

    /**
     * Returns the passed pixel coordinates in grid coordinates. This value is based on zoom.
     */
    getGridCoords(p : Point) {
        return {x: Math.floor(p.x / this.CELL_SIZE), y: Math.floor(p.y / this.CELL_SIZE)}
    }

    /** Returns the bounding box of the cells intersecting the passed rect */
    snapToGrid(r : Rectangle) {
        forceQ3(r);
        let nextX = this.CELL_SIZE * Math.ceil((r.x + r.w) / this.CELL_SIZE);
        let nextY = this.CELL_SIZE * Math.ceil((r.y + r.h) / this.CELL_SIZE);
        r.x = this.CELL_SIZE * Math.floor(r.x / this.CELL_SIZE);
        r.y = this.CELL_SIZE * Math.floor(r.y / this.CELL_SIZE);
        r.w = nextX - r.x;
        r.h = nextY - r.y;
    }

    fillCells(rect : Rectangle, style : string) {
        let oldStyle = this.g.fillStyle;
        this.g.fillStyle = style;
        for (let x = rect.x; x < rect.x + rect.w; x += this.CELL_SIZE) {
            for (let y = rect.y; y < rect.y + rect.h; y += this.CELL_SIZE) {
                this.g.fillRect(x + 1, y + 1, this.CELL_SIZE - 2, this.CELL_SIZE - 2);
            }
        }
        this.g.fillStyle = oldStyle;
    }

    clearSelect() {
        this.selectStart = null;
        this.selectEnd = null;
        this.draw();
    }

    getRectCorners(rect : Rectangle) {
        return [this.getGridCoords(rect), this.getGridCoords({x: rect.x + rect.w, y: rect.y + rect.h})];
    }

    getRectFromCorners(TL : Point, BR : Point) {
        return {
            x: TL.x,
            y: TL.y,
            w: BR.x - TL.x,
            h: BR.y - TL.y
        }
    }

    setCellType(type : CellType) {
        this.cellType = type;
        if (this.cursor === Cursor.FILL && this.selectStart && this.selectEnd) {
            let selectRect = this.getSelectRect();
            this.snapToGrid(selectRect);
            let [TL, BR] = this.getRectCorners(selectRect);
            if (type === CellType.OPEN || type === CellType.BOUNDARY || type === CellType.OBJECT || type === CellType.LABEL) {
                // TODO block intersecting items
                const obj = Object.assign({type: type}, this.getRectFromCorners(TL, BR));
                this.objects.push(obj);
                this.pushUndo({op: 'ADD', objects: [obj]});
                this.clearSelect();
            } else if (type === CellType.PIT) { // fill the selection with 2x2 pits as far as possible
                let next = this.objects.filter(x => x.type === type).length + 1;
                const objList = [];
                for (let y = TL.y; y < BR.y - 1; y += 2) {
                    for (let x = TL.x; x < BR.x - 1; x += 2) {
                        const obj = {type: type, x: x, y: y, w: 2, h: 2, label: next + ""};
                        this.objects.push(obj);
                        objList.push(obj);
                        next++;
                    }
                }
                this.pushUndo({op: 'ADD', objects: objList});
                this.clearSelect();
            } // else no action
        }
    }

    setEditing(edit : boolean) {
        this.editing = edit;
        this.draw();
    }

    setAssigning(assign : boolean) {
        this.assigning = assign;
        this.draw();
    }

    setZoom(zoom : number | null) {
        zoom = zoom ?? 1;
        this.zoom = zoom;
        this.CELL_SIZE = 20 * zoom;
        this.draw();
    }

    pushUndo(item : Action) {
        this.undoStack.push(item);
        this.redoStack = [];
    }

    undoRedo(fromStack : Action[], toStack : Action[]) {
        const swap = (op : Action) => {
            switch (op.op) {
                case "ADD":
                    op.op = "REMOVE";
                    break;
                case "REMOVE":
                    op.op = "ADD";
                    break;
                case "SHIFT":
                case "MOVE":
                    op.delta = {dx: op.delta.dx * -1, dy: op.delta.dy * -1};
                    break;
                case 'SET_LABEL':
                    const temp = op.old;
                    op.old = op.label;
                    op.label = temp;
                    break;
            }
            return op;
        }
        let op = fromStack.pop();
        if (op) {
            switch (op.op) {
                case 'ADD':
                case 'REMOVE':
                    for (let obj of op.objects) {
                        if (op.op === 'ADD') { // perform a remove
                            obj.ind = this.objects.indexOf(obj);
                            if (obj.ind > -1) {
                                this.objects.splice(obj.ind, 1)
                            }
                        } else if (op.op === 'REMOVE') { // perform an add
                            this.objects.splice(<number>obj.ind, 0, obj);
                        }
                    }
                    if (op.objects.some(x => x.type === CellType.PIT)) {
                        this.renumberObjects();
                    }
                    break;
                case 'SHIFT':
                    this.performShift({dx: op.delta.dx * -1, dy: op.delta.dy * -1});
                    break;
                case 'SET_LABEL':
                    op.obj.label = op.old;
                    break;
                case 'MOVE':
                    for (let obj of op.objects) {
                        obj.x -= op.delta.dx;
                        obj.y -= op.delta.dy;
                    }
                    break;
            }
            toStack.push(swap(op));
            this.draw();
        }
    }

    undo() {
        this.undoRedo(this.undoStack, this.redoStack);
    }

    redo() {
        this.undoRedo(this.redoStack, this.undoStack);
    }

    /**
     * Returns a list of objects that intersect the given Rectangle
     */
    getIntersectingObjects(obj : Rectangle) {
        return this.objects.filter(x => intersect(obj, x));
    }

    renumberObjects() {
        let pitCount = 0;
        const groupCounts : Record<string, number> = {};
        for (let obj of this.objects) {
            if (obj.type === CellType.PIT) {
                obj.label = (++pitCount) + "";
            }
        }
    }

    setDisplayTeamNumbers(data: Record<number, string>) {
        this.displayTeamNumbers = data;
    }

    setData(data : Cell[]) {
        this.objects = data;
        if (this.minSize) {
            const bb = this.getBoundingBox();
            for (let o of this.objects) {
                o.x -= bb.x;
                o.y -= bb.y;
            }
        }
        this.draw();
    }

    getBoundingBox() {
        let minX = this.objects.length > 0 ? this.objects.reduce((p, c) => Math.min(p, c.x), 99999) : 0;
        let minY = this.objects.length > 0 ? this.objects.reduce((p, c) => Math.min(p, c.y), 99999) : 0;
        let maxX = this.objects.length > 0 ? this.objects.reduce((p, c) => Math.max(p, c.x + c.w), -99999) : 0;
        let maxY = this.objects.length > 0 ? this.objects.reduce((p, c) => Math.max(p, c.y + c.h), -99999) : 0;
        return {x: minX, y: minY, w: maxX - minX, h: maxY - minY};
    }

    getData() : PitMapData {
        const bb = this.getBoundingBox();
        return JSON.parse(JSON.stringify({
            objects: this.objects,
            minX: bb.x,
            minY: bb.y,
            width: bb.w,
            height: bb.h,
            numbers: true,
            addresses: true
        })); // deep copy
    }

    performShift(delta : Delta) {
        for (let obj of this.objects) {
            obj.x += delta.dx;
            obj.y += delta.dy;
        }
        this.draw();
    }

    shift(dir : 'up' | 'right' | 'down' | 'left') {
        const delta = {
            up: {dx: 0, dy: -1},
            right: {dx: 1, dy: 0},
            down: {dx: 0, dy: 1},
            left: {dx: -1, dy: 0},
        }[dir]
        this.pushUndo({op: "SHIFT", delta: delta});
        this.performShift(delta);
    }

    setPitClickCallback(cb : PitClickCallback) {
        this.pitClickCallback = cb;
    }

    setPitLabelMode(mode : LabelMode) {
        this.pitLabelMode = mode;
        this.draw();
    }

    setPrintPitColors(printColors: boolean) {
        this.printPitColors = printColors;
    }

    setPitAssignCallback(cb : PitAssignCallback) {
        this.pitAssignCallback = cb;
    }

    setIncrement(inc: number) {
        this.increment = inc;
    }

    getIncrement() {
        return this.increment;
    }

    setActiveGroup(prefix: string) {
        this.activeGroup = prefix;
    }

    getActiveGroup() {
        return this.activeGroup;
    }

    getPitObjects() {
        return this.objects.filter(x => x.type === CellType.PIT);
    }

    setAssignError(cb : ErrorCallback) {
        this.assignError = cb;
    }

    assign(pits : Cell[], mode : LabelMode, val : string | null) {
        if (mode === LabelMode.NUMBER) { // swap pit objects.
            const pit = pits[0]; // only 1 at a time.
            if (pit.label === val || pit.label === (val + "")) { //noop
                console.log("Pit set to current value", val);
                return;
            }
            const others = this.getPitObjects().filter(x => x.label === val && x !== pit);
            if (others.length === 0 && this.assignError) {
                this.assignError({errType: PitMap.ERROR_ILLEGAL_NUMBER, number: val, max: this.getPitObjects().length});
                return;
            }
            if (others.length > 1 && this.assignError) {
                this.assignError({errType: PitMap.ERROR_DUPLICATE_PIT, number: val});
                return;
            }
            const other = others[0];
            const otherClone = Object.assign({}, other);
            // swap the values of the two objects, setting the new labels appropriately
            Object.assign(other, pit, {label: val});
            Object.assign(pit, otherClone, {label: pit.label});
            this.renumberObjects();
        } else if (mode === LabelMode.ADDRESS) {
            if (!val && val !== null) {
                val = null;
            }
            pits.forEach(pit => pit.address = val ? val : undefined);
        } else if (mode === LabelMode.TEAM) {
            if (pits.length > 1 && this.assignError) { // if this happens our assignment editor code messed up, so reuse the contact support" duplicate error msg
                this.assignError({errType: PitMap.ERROR_DUPLICATE_PIT, number: val});
                return;
            }
            pits[0].team = parseInt(val ?? "") || undefined;
        } else if (mode === LabelMode.COLOR) {
            pits.forEach(pit => pit.color = val ? val : undefined);
        }
        this.draw();
    }

    findTeam(team : string) {
        const teamNum = parseInt(team);
        return this.getPitObjects().find(x => x.team === teamNum);
    }

    setHighlighted(obj : Cell) {
        this.highlighted = obj;
        this.draw();
    }

    findPit(num : string) {
        let numInt = parseInt(num);
        return this.getPitObjects().find(x => parseInt(x.label || "") === numInt);
    }

    getFullAddress(pit : Cell) {
        return pit.address ?? "";
    }

    getPitAssignments(): Record<string, PitAssignment> {
        const assignments : Record<string, PitAssignment> = {};
        this.getPitObjects().forEach(pit => {
            if (pit.team) {
                assignments[pit.team] = {
                    number: parseInt(pit.label || ""),
                    address: this.getFullAddress(pit),
                    team: pit.team
                };
            }
        })
        return assignments;
    }

    getCanvas() {
        return this.canvas;
    }

    autoAssignPits(type : AutoAssignmentType, teams : number[]) {
        if (type === AutoAssignmentType.CLEAR) {
            this.objects.filter(x => x.type === CellType.PIT).forEach((v) => v.team = undefined);
            this.draw();
            return;
        }
        const a2i = (s? : string | null) => parseInt(s ?? "0");
        const pits = this.objects.filter(x => x.type === CellType.PIT).sort((a, b) => a2i(a.label) - a2i(b.label));
        let unassignedTeams = teams.filter(t => !pits.some(p => p.team === t)).sort((a, b) => a - b);
        if (type === AutoAssignmentType.DESCENDING) {
            unassignedTeams.reverse();
        } else if (type == AutoAssignmentType.RANDOM) { // stil only fills first n
            // shuffle - Schwartzian transform approach from https://stackoverflow.com/a/46545530
            unassignedTeams = unassignedTeams.map(value => ({ value, sort: Math.random() }))
                .sort((a, b) => a.sort - b.sort).map(({ value }) => value);
        }
        let i = 0;
        for (let cell of pits) {
            if (!cell.team) {
                if (i < unassignedTeams.length) {
                    cell.team = unassignedTeams[i++];
                } else {
                    break;
                }
            }
        }
        this.draw();
    }

    prepareForPrint() {
        this.printing = true;
        this.draw();
    }

    donePrinting() {
        this.printing = false;
        this.draw();
    }
}

function intersect(r1 : Rectangle, r2 : Rectangle) {
    let left = r1.x + r1.w < r2.x;
    let right = r1.x >= r2.x + r2.w;
    let above = r1.y + r1.h < r2.y;
    let below = r1.y >= r2.y + r2.h;
    return !(left || right || above || below);
}

function forceQ3(r : Rectangle) {
    if (r.w < 0) {
        r.x += r.w;
        r.w *= -1;
    }
    if (r.h < 0) {
        r.y += r.h;
        r.h *= -1;
    }
}



